8	export type Response = SuccessResponse | ErrorResponse
9	
10	export type SuccessResponse = {
11	  jsonrpc: '2.0'
12	  result: any
13	  id: number
14	}
15	
16	export type ErrorResponse = {
17	  jsonrpc: '2.0'
18	  error: {
19	    code: number
20	    message: string
21	    data: any
22	  }
23	  id: number
24	}
