import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to its TypeScript equivalent. */
export function scalarToTs(type: string): string {
  switch (type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Bytes':
      return 'Uint8Array'
    case 'Decimal':
      // Decimal is serialised as a string over JSON to avoid precision loss.
      return 'string'
    case 'Json':
      return 'unknown'
    default:
      return 'unknown'
  }
}

/**
 * Returns the TypeScript property declaration for a DMMF field, or `null`
 * when the field is a relation (kind `'object'`) and should be omitted.
 */
export function fieldToTs(field: DMMF.Field): string | null {
  if (field.kind === 'object' || field.kind === 'unsupported') {
    return null
  }

  let tsType: string
  if (field.kind === 'enum') {
    tsType = field.type
