import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'

import { renderEnum, renderInterface, renderModelInputTypes, renderModelMethods } from './template'

/** Runs the REST client generator and writes `rest-client.ts` to the configured output directory. */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('No output directory configured for @prisma/generator-rest-client')
  }

  await fs.mkdir(outputDir, { recursive: true })

  const { datamodel } = options.dmmf
  const sections: string[] = ['// Generated by @prisma/generator-rest-client – do not edit by hand.\n']

  for (const datamodelEnum of datamodel.enums) {
    sections.push(renderEnum(datamodelEnum))
  }

  for (const model of datamodel.models) {
    sections.push(renderInterface(model))
  }

  for (const model of datamodel.models) {
    sections.push(renderModelInputTypes(model))
  }

  const methodBlocks = datamodel.models.map(renderModelMethods).join('\n')
  const classBody = [
    'export class RestClient {',
    '  #baseUrl: string',
    '',
    '  constructor(baseUrl: string) {',
    '    this.#baseUrl = baseUrl',
    '  }',
    methodBlocks,
    '}',
  ].join('\n')
  sections.push(classBody)

  const output = sections.join('\n\n') + '\n'
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), output, 'utf-8')
}

